    analysisButtons.forEach(btn => {
        btn.addEventListener('click', () => {
            analysisButtons.forEach(b => b.classList.remove('active'));
            btn.classList.add('active');
            const type = btn.getAttribute('data-type');
            showAnalysisInputs(type);
        });
    });
